#include <stdlib.h>
#include <openssl/evp.h>
#include <openssl/rsa.h>
#include <openssl/err.h>

/**
 * OpenSSL 3.0 implementation using high-level EVP APIs.
 * 1. Generates 2048-bit RSA key.
 * 2. Signs SHA-256 digest of a message.
 * 3. Extracts modulus 'n' as a BIGNUM using parameter APIs.
 */

void handle_errors() {
    ERR_print_errors_fp(stderr);
    abort();
}

int main() {
    // 1. Generate 2048-bit RSA Key
    EVP_PKEY_CTX *kctx = EVP_PKEY_CTX_new_id(EVP_PKEY_RSA, NULL);
    if (!kctx) handle_errors();

    if (EVP_PKEY_keygen_init(kctx) <= 0) handle_errors();
    if (EVP_PKEY_CTX_set_rsa_keygen_bits(kctx, 2048) <= 0) handle_errors();

    EVP_PKEY *pkey = NULL;
    if (EVP_PKEY_keygen(kctx, &pkey) <= 0) handle_errors();

    printf("Successfully generated 2048-bit RSA key.\n");

    // 2. Sign the SHA-256 digest of a message
    const char *msg = "This is a secure message to be signed.";
    size_t msg_len = strlen(msg);
    size_t sig_len;

    EVP_MD_CTX *mctx = EVP_MD_CTX_new();
    if (!mctx) handle_errors();

    // Initialize signing operation with SHA-256
    if (EVP_DigestSignInit(mctx, NULL, EVP_sha256(), NULL, pkey) <= 0) handle_errors();
    if (EVP_DigestSignUpdate(mctx, msg, msg_len) <= 0) handle_errors();

    // Determine signature length (first call to Final with NULL)
    if (EVP_DigestSignFinal(mctx, NULL, &sig_len) <= 0) handle_errors();

    unsigned char *sig = malloc(sig_len);
    if (!sig) handle_errors();

    // Perform actual signing
    if (EVP_DigestSignFinal(mctx, sig, &sig_len) <= 0) handle_errors();

    printf("Message signed. Signature length: %zu bytes\n", sig_len);

    // 3. Extract the modulus 'n' as a BIGNUM
    // In OpenSSL 3.0, the recommended way to access RSA parameters 
    // without using the deprecated RSA* struct is via EVP_PKEY_get_bn_param.
    BIGNUM *n = NULL;
    if (EVP_PKEY_get_bn_param(pkey, "n", &n) <= 0) {
        fprintf(stderr, "Failed to extract modulus 'n'\n");
        handle_errors();
    }

    char *n_hex = BN_bn2hex(n);
    printf("Modulus (n) extracted: %s\n", n_hex ? n_hex : "NULL");

    // Cleanup
    OPENSSL_free(n_hex);
    BN_free(n);
    EVP_PKEY_free(pkey);
    EVP_PKEY_CTX_free(kctx);
    EVP_MD_CTX_free(mctx);
    free(sig);

    return 0;
}
