params[1] = OSSL_PARAM_construct_BN(OSSL_PKEY_RSA_E, e);
params[2] = OSSL_PARAM_construct_BN(OSSL_PKEY_RSA_D, d);
params[3] = OSSL_PARAM_construct_end();

// Construct the new key
