int main() {
    const char *method_name = "HMAC";
    const char *digest_name = "SHA256";
    unsigned char *key = (unsigned char *)"secret_key";
    size_t key_len = strlen((char *)key);
    unsigned char *msg = (unsigned char *)"Hello, OpenSSL 3.0!";
    size_t msg_len = strlen((char *)msg);

    EVP_MAC *mac = NULL;
    EVP_MAC_CTX *ctx = NULL;
    unsigned char md[EVP_MAX_MD_SIZE];
    size_t md_len = 0;

    // 1. Fetch the MAC implementation
    mac = EVP_MAC_fetch(NULL, method_name, "default");
    if (mac == NULL) {
        fprintf(stderr, "Failed to fetch HMAC\n");
        return 1;
    }

    // 2. Create the context
    ctx = EVP_MAC_CTX_new(mac);
    if (ctx == NULL) {
        fprintf(stderr, "Failed to create context\n");
        EVP_MAC_free(mac);
        return 1;
    }

    // 3. Initialize with key and digest via OSSL_PARAM
    OSSL_PARAM params[3];
    params[0] = OSSL_PARAM_construct1("key", key, key_len);
    params[1] = OSSL_PARAM_construct_utf8_string("digest", digest_name, 0);
    params[2] = OSSL_PARAM_construct2(NULL);

    if (EVP_MAC_init(ctx, params) <= 0) {
        fprintf(stderr, "Failed to initialize MAC\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // 4. Update (feeding the message)
    if (EVP_MAC_update(ctx, msg, msg_len) <= 0) {
        fprintf(stderr, "Failed to update MAC\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // 5. Finalize (computing the result)
    if (EVP_MAC_final(ctx, md, &md_len, sizeof(md)) <= 0) {
        fprintf(stderr, "Failed to finalize MAC\n");
        EVP_MAC_CTX_free(ctx);
        EVP_MAC_free(mac);
        return 1;
    }

    // Print result in hex
    printf("HMAC-SHA256: ");
    for (size_t i = 0; i < md_len; i++) {
        printf("%02x", md[i]);
    }
    printf("\n");

    // Cleanup
    OSSL_PARAM_free(params);
    EVP_MAC_CTX_free(ctx);
    EVP_MAC_free(mac);

    return 0;
}
